def heap_queue_smallest(numbers,k):
    # write your code here
    if k>len(numbers):
        return []
    heap = []
    for i in range(k):
        heapq.heappush(heap,numbers[i])
    for i in range(k,len(numbers)):
        if numbers[i]<heap[0]:
            heapq.heappop(heap)
            heapq.heappush(heap,numbers[i])
    return heap
