def no_of_subsequences(arr, k):
    # Write your code here
    n = len(arr)
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, n + 1):
        for j in range(i, 0, -1):
            if arr[j - 1] * arr[i - 1] < k:
                dp[i] += dp[j - 1]
    return dp[n]
